import pymysql
import functions_framework
from typing import Dict, Any, List

@functions_framework.http
def search_api(request):
    """HTTP Cloud Function that queries Cloud SQL MySQL database with dynamic filters."""
    
    # Database connection configuration
    db_config = {
        'host': 'your-cloud-sql-instance-connection-name',
        'user': 'your-username',
        'password': 'your-password',
        'database': 'your-database-name',
        'charset': 'utf8mb4'
    }
    
    # Get request parameters
    request_args = request.args
    
    # Build dynamic WHERE clause
    where_conditions = []
    params = []
    
    # Process each parameter to build dynamic query
    for key, value in request_args.items():
        if key != 'table' and key != 'limit' and key != 'offset':
            if isinstance(value, list):
                # Handle multiple values for same parameter
                placeholders = ','.join(['%s'] * len(value))
                where_conditions.append(f"{key} IN ({placeholders})")
                params.extend(value)
            else:
                # Handle single value
                where_conditions.append(f"{key} = %s")
                params.append(value)
    
    # Build base query
    table_name = request_args.get('table', 'default_table')
    query = f"SELECT * FROM {table_name}"
    
    # Add WHERE clause if conditions exist
    if where_conditions:
        query += " WHERE " + " AND ".join(where_conditions)
    
    # Add ORDER BY if provided
    order_by = request_args.get('order_by')
    if order_by:
        query += f" ORDER BY {order_by}"
    
    # Add LIMIT and OFFSET
    limit = request_args.get('limit', 100)
    offset = request_args.get('offset', 0)
    query += f" LIMIT {limit} OFFSET {offset}"
    
    # Connect to database and execute query
    try:
        connection = pymysql.connect(**db_config)
        with connection.cursor(pymysql.cursors.DictCursor) as cursor:
            cursor.execute(query, params)
            results = cursor.fetchall()
        
        connection.close()
        
        return {
            'status': 'success',
            'data': results,
            'count': len(results)
        }
        
    except Exception as e:
        return {
            'status': 'error',
            'message': str(e)
        }